{"code":"def untar_file(path, fn):
    """
    Extracts a tar archive into a specified directory using the system tar command.
    Automatically detects compression formats and creates the target directory if it doesn't exist.
    """
    if not os.path.exists(path):
        try:
            os.makedirs(path)
        except Exception as e:
            raise GenipeError(f"Failed to create directory {path}: {e}")

    # Determine flags based on file extension
    if fn.endswith('.tar.gz') or fn.endswith('.tgz'):
        flags = '-xzf'
    elif fn.endswith('.tar.bz2') or fn.endswith('.tbz'):
        flags = '-xjf'
    else:
        flags = '-xf'

    try:
        # Using check_call as imported in context
        check_call(['tar', flags, fn, '-C', path])
    except CalledProcessError as e:
        raise GenipeError(f"Failed to extract {fn} to {path}: {e}")
    except Exception as e:
        raise GenipeError(f"An error occurred while extracting {fn}: {e}")
